-- silver.nfhs5_district: cleaned NFHS-5 district indicators.
-- Rules (AGENTS.md gotcha #2): '*' (suppressed) -> NULL, never 0; parenthesised
-- small-sample values kept but counted in nfhs_small_sample_cols (low-confidence);
-- all numeric-bearing string columns try_cast to DOUBLE. Adds normalized join keys.
-- GENERATED from information_schema (49 numeric-string cols cleaned).
CREATE OR REPLACE TABLE mdp.silver.nfhs5_district AS
SELECT
  `district_name`,
  `state_ut`,
  trim(regexp_replace(upper(trim(`district_name`)), '[^A-Z0-9]+', ' ')) AS norm_district,
  trim(regexp_replace(upper(trim(`state_ut`)),      '[^A-Z0-9]+', ' ')) AS norm_state,
