tion_5y_pct`) LIKE '(%)' THEN 1 ELSE 0 END + CASE WHEN trim(`child_12_23m_fully_vaccinated_based_on_information_from_eit_pct`) LIKE '(%)' THEN 1 ELSE 0 END + CASE WHEN trim(`child_12_23m_fully_vaccinated_based_on_information_from_vax_pct`) LIKE '(%)' THEN 1 ELSE 0 END + CASE WHEN trim(`child_12_23m_who_have_received_bcg_pct`) LIKE '(%)' THEN 1 ELSE 0 END + CASE WHEN trim(`child_12_23m_who_have_received_3_doses_of_polio_vaccine_pct`) LIKE '(%)' THEN 1 ELSE 0 END + CASE WHEN trim(`child_12_23m_who_have_received_3_doses_of_penta_or_dpt_vacc_pct`) LIKE '(%)' THEN 1 ELSE 0 END + CASE WHEN trim(`child_12_23m_who_have_received_the_first_dose_of_mcv_mcv_pct`) LIKE '(%)' THEN 1 ELSE 0 END + CASE WHEN trim(`child_24_35m_who_have_received_a_second_dose_of_mcv_mcv_pct`) LIKE '(%)' THEN 1 ELSE 0 END + CASE WHEN trim(`child_12_23m_who_have_received_3_doses_of_rotavirus_vaccine_pct`) LIKE '(%)' THEN 1 ELSE 0 END + CASE WHEN trim(`child_12_23m_who_have_received_3_doses_of_penta_or_hepatiti_pct`) LIKE '(%)' THEN 1 ELSE 0 END + CASE WHEN trim(`child_9_35m_who_received_a_vit_a_in_the_last_6_months_pct`) LIKE '(%)' THEN 1 ELSE 0 END + CASE WHEN trim(`child_12_23m_who_received_most_of_their_vaccinations_in_a_p_pct`) LIKE '(%)' THEN 1 ELSE 0 END + CASE WHEN trim(`child_12_23m_who_received_most_of_their_vaccinations_in_a_2_pct`) LIKE '(%)' THEN 1 ELSE 0 END + CASE WHEN trim(`children_with_diarrhoea_2wk_who_received_oral_rehydration_s_pct`) LIKE '(%)' THEN 1 ELSE 0 END + CASE WHEN trim(`children_with_diarrhoea_2wk_who_received_zinc_child_u5_pct`) LIKE '(%)' THEN 1 ELSE 0 END + CASE WHEN trim(`children_with_diarrhoea_2wk_taken_to_a_health_facility_or_h_pct`) LIKE '(%)' THEN 1 ELSE 0 END + CASE WHEN trim(`children_with_fever_or_symptoms_of_ari_2wk_taken_to_a_healt_pct`) LIKE '(%)' THEN 1 ELSE 0 END + CASE WHEN trim(`children_under_age_3_years_breastfed_within_one_hour_of_bir_pct`) LIKE '(%)' THEN 1 ELSE 0 END + CASE WHEN trim(`child_u6m_exclusively_breastfed_pct`) LIKE '(%)' THEN 1 ELSE 0 EN